import React, { useEffect, useState, useCallback } from 'react';
import api from '../api/axiosConfig';
import { useTheme } from '../context/ThemeContext';
import ReactMarkdown from 'react-markdown';
import {
  Trash2,
  Download,
  Archive,
  Calendar,
  ShieldCheck,
  Eye,
  X,
  BarChart3,
  AlignLeft
} from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { isDark } = useTheme();
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  /* ───────── Fetch History ───────── */
  const fetchHistory = useCallback(async () => {
    try {
      const res = await api.get('/portfolio/history');
      const data = res.data?.data || res.data || [];
      setHistory(data.filter(item => item && item.id));
    } catch {
      toast.error('Unable to load strategy history');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchHistory();
  }, [fetchHistory]);

  /* ───────── Delete ───────── */
  const handleDelete = async (id) => {
    if (!window.confirm('Delete this strategy permanently?')) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success('Strategy deleted');
    } catch {
      toast.error('Delete failed');
    }
  };

  /* ───────── Download ───────── */
  const handleDownload = async (item) => {
    try {
      const res = await api.post('/portfolio/export', item, {
        responseType: 'blob'
      });
      const blob = new Blob([res.data], { type: 'application/pdf' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `Strategy_${item.id}.pdf`;
      a.click();
      URL.revokeObjectURL(url);
    } catch {
      toast.error('Export failed');
    }
  };

  /* ───────── Lock Scroll on Modal ───────── */
  useEffect(() => {
    document.body.style.overflow = selectedItem ? 'hidden' : 'auto';
    return () => (document.body.style.overflow = 'auto');
  }, [selectedItem]);

  if (loading) {
    return <div style={centerStyle}>Loading strategy vault…</div>;
  }

  return (
    <div style={containerStyle}>
      {/* Header */}
      <div style={headerRow}>
        <h2 style={headerStyle}>
          <Archive size={28} /> Strategy Vault
        </h2>
        <div style={vaultBadge}>
          <BarChart3 size={16} /> {history.length} Saved
        </div>
      </div>

      {/* List */}
      <div style={listStyle}>
        {history.length === 0 && (
          <div style={emptyState}>No saved strategies yet.</div>
        )}

        {history.map(item => (
          <div key={item.id} style={cardStyle}>
            <div style={cardMeta}>
              <div style={{ display: 'flex', gap: '16px' }}>
                <span style={metaText}>
                  <Calendar size={14} />
                  {new Date(item.created_at).toLocaleDateString()}
                </span>
                <span style={metaText}>
                  <ShieldCheck size={14} />
                  Risk: {item.risk_score ?? 'N/A'}
                </span>
              </div>

              <div style={cardActions}>
                <button
                  style={iconBtn}
                  onClick={() => setSelectedItem(item)}
                >
                  <Eye size={20} />
                </button>

                <button
                  style={iconBtn}
                  onClick={() => handleDownload(item)}
                >
                  <Download size={20} />
                </button>

                <button
                  style={deleteBtn}
                  onClick={() => handleDelete(item.id)}
                >
                  <Trash2 size={20} />
                </button>
              </div>
            </div>

            <h4 style={titleStyle}>{item.goal || 'Untitled Strategy'}</h4>

            <p style={labelSmall}>
              <AlignLeft size={12} /> Summary
            </p>

            <ReactMarkdown>
              {item.summary || '_No summary available._'}
            </ReactMarkdown>
          </div>
        ))}
      </div>

      {/* Modal */}
      {selectedItem && (
        <div style={modalOverlay(isDark)}>
          <div style={modalContent(isDark)}>
            <div style={modalHeader}>
              <span style={modalId}>Strategy #{selectedItem.id}</span>
              <button
                style={closeBtn}
                onClick={() => setSelectedItem(null)}
              >
                <X size={24} />
              </button>
            </div>

            <div style={modalBody}>
              <h3 style={modalTitle}>
                {selectedItem.goal || 'Untitled Strategy'}
              </h3>

              <p style={labelSmall}>
                <AlignLeft size={14} /> Rationale
              </p>

              {selectedItem.rationale ? (
                <ReactMarkdown>{selectedItem.rationale}</ReactMarkdown>
              ) : (
                <p style={{ opacity: 0.6, fontStyle: 'italic' }}>
                  No detailed reasoning stored for this strategy.
                </p>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

/* ───────── Styles (CLICK-SAFE) ───────── */

const containerStyle = { padding: '3rem 1.5rem', maxWidth: '1200px', margin: '0 auto' };
const headerRow = { display: 'flex', justifyContent: 'space-between', marginBottom: '2rem' };
const headerStyle = { display: 'flex', gap: '12px', fontSize: '1.8rem', fontWeight: 800 };
const vaultBadge = { display: 'flex', gap: '8px', fontSize: '0.85rem', fontWeight: 700 };
const listStyle = { display: 'flex', flexDirection: 'column', gap: '2rem' };

const cardStyle = {
  padding: '2rem',
  borderRadius: '18px',
  border: '1px solid var(--surface-border)',
  position: 'relative',
  pointerEvents: 'auto'
};

const cardMeta = { display: 'flex', justifyContent: 'space-between', marginBottom: '1rem' };
const metaText = { fontSize: '0.85rem', display: 'flex', gap: '6px' };

const cardActions = { display: 'flex', gap: '12px' };

const iconBtn = {
  background: 'none',
  border: 'none',
  cursor: 'pointer',
  zIndex: 10,
  position: 'relative',
  pointerEvents: 'auto'
};

const deleteBtn = { ...iconBtn, color: '#ef4444' };

const titleStyle = { fontSize: '1.3rem', fontWeight: 700, marginBottom: '0.8rem' };
const labelSmall = { fontSize: '0.75rem', fontWeight: 700, opacity: 0.7, marginBottom: '0.4rem' };
const emptyState = { textAlign: 'center', opacity: 0.6 };
const centerStyle = { height: '70vh', display: 'flex', alignItems: 'center', justifyContent: 'center' };

const modalOverlay = (isDark) => ({
  position: 'fixed',
  inset: 0,
  background: isDark ? 'rgba(0,0,0,0.9)' : 'rgba(255,255,255,0.9)',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  zIndex: 9999,
  pointerEvents: 'auto'
});

const modalContent = (isDark) => ({
  width: '90%',
  maxWidth: '900px',
  background: isDark ? '#000' : '#fff',
  borderRadius: '18px'
});

const modalHeader = {
  padding: '1.5rem',
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center'
};

const modalId = { fontSize: '0.85rem', fontWeight: 700 };
const modalBody = { padding: '2rem', maxHeight: '70vh', overflowY: 'auto' };
const modalTitle = { fontSize: '1.6rem', fontWeight: 800, marginBottom: '1.2rem' };
const closeBtn = { background: 'none', border: 'none', cursor: 'pointer' };

export default VaultPage;
